+const OUTPUT_SCHEMA_VERSION: &str = "franken-engine.franken_react_package_cohort.v1";
+
+enum CliAction {
+    Help,
+    Run { out_dir: PathBuf },
+}
+
+#[derive(Debug, Clone, Serialize)]
+struct CommandOutput {
+    schema_version: String,
+    out_dir: String,
+    react_package_cohort_matrix: String,
+    trace_ids: String,
+    run_manifest: String,
+    events_jsonl: String,
+    commands_txt: String,
+    matrix_hash: String,
+    package_count: usize,
+    edge_case_count: usize,
+}
+
+fn main() {
+    if let Err(error) = run() {
+        eprintln!("{error}");
+        std::process::exit(1);
+    }
+}
+
+fn run() -> Result<(), String> {
+    let args: Vec<String> = env::args().collect();
+    let out_dir = match parse_args(&args[1..])? {
+        CliAction::Help => {
+            println!("{}", help_text());
+            return Ok(());
+        }
+        CliAction::Run { out_dir } => out_dir,
+    };
+
+    let artifacts =
+        write_react_package_cohort_bundle(&out_dir, &args).map_err(|error| error.to_string())?;
+    let output = CommandOutput {
+        schema_version: OUTPUT_SCHEMA_VERSION.to_string(),
+        out_dir: artifacts.out_dir.display().to_string(),
+        react_package_cohort_matrix: artifacts.matrix_path.display().to_string(),
+        trace_ids: artifacts.trace_ids_path.display().to_string(),
+        run_manifest: artifacts.run_manifest_path.display().to_string(),
+        events_jsonl: artifacts.events_path.display().to_string(),
+        commands_txt: artifacts.commands_path.display().to_string(),
+        matrix_hash: artifacts.matrix_hash,
+        package_count: artifacts.package_count,
+        edge_case_count: artifacts.edge_case_count,
+    };
+    let rendered = serde_json::to_string_pretty(&output).map_err(|error| error.to_string())?;
+    println!("{rendered}");
+    Ok(())
+}
+
+fn parse_args(args: &[String]) -> Result<CliAction, String> {
+    if args.is_empty() {
+        return Err(help_text());
+    }
+
+    let mut out_dir: Option<PathBuf> = None;
+    let mut index = 0usize;
+    while index < args.len() {
+        match args[index].as_str() {
+            "-h" | "--help" => return Ok(CliAction::Help),
+            "--out-dir" => {
+                let Some(value) = args.get(index + 1) else {
+                    return Err("--out-dir requires a path".to_string());
+                };
+                out_dir = Some(PathBuf::from(value));
+                index += 2;
+            }
+            other => {
+                return Err(format!(
+                    "unrecognized argument `{other}`\n\n{}",
+                    help_text()
+                ));
+            }
+        }
+    }
+
+    out_dir
+        .map(|out_dir| CliAction::Run { out_dir })
+        .ok_or_else(|| format!("missing required --out-dir\n\n{}", help_text()))
+}
+
+fn help_text() -> String {
+    "Usage: franken_react_package_cohort --out-dir <DIR>".to_string()
+}

