+    write_atomic(&events_path, events_jsonl.as_bytes())?;
+    write_atomic(&commands_path, commands_buf.as_bytes())?;
+    write_atomic(&run_manifest_path, &manifest_bytes)?;
+
+    Ok(ReactCohortBundleArtifacts {
